class StockPrice {
    Map<Integer, Integer> priceMap;
    Map<Integer, Integer> timestampMap;

    public StockPrice() {
        priceMap = new HashMap<>();
        timestampMap = new HashMap<>();
    }

    public void update(int timestamp, int price) {
        priceMap.put(timestamp, price);
        timestampMap.put(timestamp, timestampMap.getOrDefault(timestamp, 0) + 1);
    }

    public int current() {
        int maxTimestamp = 0;
        for (int timestamp : timestampMap.keySet()) {
            if (timestamp > maxTimestamp) {
                maxTimestamp = timestamp;
            }
        }
        return priceMap.get(maxTimestamp);
    }

    public int maximum() {
        int maxPrice = Integer.MIN_VALUE;
        for (int price : priceMap.values()) {
            if (price > maxPrice) {
                maxPrice = price;
            }
        }
        return maxPrice;
    }

    public int minimum() {
        int minPrice = Integer.MAX_VALUE;
        for (int price : priceMap.values()) {
            if (price < minPrice) {
                minPrice = price;
            }
        }
        return minPrice;
    }
}
```
